/*\n  # Create conversion_events table for analytics tracking\n\n  1. New Tables\n    - `conversion_events`\n      - `id` (uuid, primary key)\n      - `event_type` (text) - Type of conversion event (e.g., 'zip_entered', 'report_generated', 'inspection_booked')\n      - `zip_entered` (text, nullable) - ZIP code if applicable\n      - `inspection_booked` (boolean, default false) - Whether an inspection was booked\n      - `session_id` (text, nullable) - Session identifier for tracking user journeys\n      - `user_agent` (text, nullable) - Browser user agent string\n      - `created_at` (timestamptz, default now())\n\n  2. Security\n    - Enable RLS on `conversion_events` table\n    - Add policy allowing anonymous inserts for tracking\n    - Add policy for authenticated users to read their own events\n*/\n\nCREATE TABLE IF NOT EXISTS conversion_events (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  event_type text NOT NULL,\n  zip_entered text,\n  inspection_booked boolean DEFAULT false,\n  session_id text,\n  user_agent text,\n  created_at timestamptz DEFAULT now()\n);
\n\nALTER TABLE conversion_events ENABLE ROW LEVEL SECURITY;
\n\nCREATE POLICY "Allow anonymous inserts for analytics"\n  ON conversion_events\n  FOR INSERT\n  TO anon\n  WITH CHECK (true);
\n\nCREATE POLICY "Allow service role full access"\n  ON conversion_events\n  FOR ALL\n  TO service_role\n  USING (true)\n  WITH CHECK (true);
;
